  X, Y: Integer);
var
  i:integer;
  obj:selectSrc;
  h:boolean;
begin
  i:=signalsLB.ItemAtPos(point(x,y),true);
  h:=false;
  if i>=0 then
  begin
    obj := selectSrc(SignalsLB.Items.Objects[i]);
    if obj.utsSignals.Count=0 then
    begin
      h:=true;
