function selectSrc.getUTS(name: string): cwpsignal;
var
  I: Integer;
  s:utssignal;
begin
  result:=nil;
  for I := 0 to utsSignals.Count - 1 do
  begin
    s:=utssignal(utsSignals.Objects[i]);
    if s.s.name=name then
    begin
      result:=s.s;
    end;
  end;
end;

procedure TCorrectUTSFrm.DelBtnClick(Sender: TObject);
