// алгоритм не знает списка сигналов обработки (он получает по одному
  // сигналу перед вызовом). Работу с группой сигналов реализует форма
  TCounterOper = class(TAutoObject, IWPExtOper)
  private
    m_mng: cBaseObjmng;
    m_Hi, m_Lo:double;
    m_FltTrend:boolean;
    m_wnd:double;
    T1, t2:double;
    // 0 - user; 1 - allTest; 2 - Cursors
    Ttype:integer;
  public
    procedure GetError(out pnerrcode: integer; out perrstr: WideString);safecall;
    procedure OnApply; safecall;
    procedure OnClose; safecall;
    procedure Exec(const psrc1, psrc2: IDispatch; out pdst1, pdst2: IDispatch);safecall;
    procedure OnSetup(hwndparent: integer; out phwnd: integer); safecall;
    procedure GetPropStr(out pstr: WideString); safecall;
    procedure SetPropStr(const str: WideString); safecall;
  public
    function GetPropStrF(out pstr: WideString):string;
    function Execute(const psrc1: IDispatch): boolean;
    procedure link(m:cbaseObjMng);
    procedure Setup;
    Constructor create;
    destructor destroy;
  end;

var
  CounterFrm: TCounterFrm;

const
  c_OperName = 'Counter';

implementation

uses
{$R *.dfm}
  uLocalizationHelper,
  uWpExtPack;



{ TExtCounter }

constructor TCounterOper.create;
begin
  m_Hi := 0.7;
  m_Lo := 0.3;
  m_wnd:=1;
  m_FltTrend:=false;
end;

destructor TCounterOper.destroy;
begin
  inherited;
end;

function TCounterOper.Execute(const psrc1: IDispatch): boolean;
var
  D: IDispatch;
begin
  result := true;
  Exec(psrc1, psrc1, D, D);
end;


function GetMTrend(const src: olevariant; dt:double): iwpsignal;
var
  opts, str:string;
  v:cString;
  pars:tstringlist;
  ind:integer;
  oper:iwpoperator;
  r1, r2, opt, err: olevariant;
  s1:iwpsignal;
begin
  result:=nil;
  //12:12:51|Выполнение алгоритма ""|typeRez=6,nPoints=4800,bEquivMag=0,
  opts:='typeRez=6,'+ // Re Im спектр
         'nPoints=4800,'+ // размер порции
          'nOfs=4800,'+ // смещение порции
         'bEquivMag=0';

  pars:=ParsStrParamNoSort(opts, ',');
  if FindInPars(pars,'nPoints',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    v.str:=floattostr(round(dt/src.deltax));
  end;
  if FindInPars(pars,'nOfs',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    v.str:=floattostr(round(dt/src.deltax));
  end;
  str:=ParsToStr(pars);
  pars.Destroy;
  oper:= WP.GetObject('/VibroOpers/Последовательная обработка (тренды)') as IWPOperator;
  if (Assigned(oper)) then
  begin
    oper.loadProperties(str);
    oper.Exec(src,src,refvar(r1),refvar(r2));

    s1 := iwpsignal(TVarData(r1).VPointer);
    result:=s1;
  end;
end;

procedure TCounterOper.Exec(const psrc1, psrc2: IDispatch; out pdst1, pdst2: IDispatch);
var
  s, res,
  trendM, trendA: iwpsignal;

  i, ind, count: integer;

  val, max, min, mean, h,l, pp, fs: double;
  t, dt:double;
  wstr:widestring;

  // 0 - start, 1 - triggered , 2 end
  state:integer;
begin
  s := iwpsignal(psrc1);
  res := iwpsignal(wp.CreateSignal(vt_r8));
  res.StartX := s.StartX;
  res.DeltaX := s.DeltaX;
  res.size := s.size;
  fs:=1/s.DeltaX;
  trendM:=TrendMO(s, round(m_wnd*fs));
  trendA:=TrendAmp(s, round(m_wnd*fs));
  mean:=GetMO(s);
  min:=s.MinY;
  max:=s.MaxY;
  pp:=max-min;
  h:=pp*m_hi+min;
  l:=pp*m_lo+min;
  count := 0;
  state:=0;

  dt:=s.DeltaX;
  t:=s.MinX;
  for i := 0 to s.size - 1 do
  begin
    if m_FltTrend then
    begin
      mean:=trendM.GetYX(t, 1);
      pp:=2*trendA.GetYX(t, 1);
      min:=mean-pp/2;
      h:=pp*m_hi+min;
      l:=pp*m_lo+min;
    end;
    val := s.GetY(i);
    case state of
      0: //search
      begin
        if val>l then
        begin
          state:=1;
          if val>h then
          begin
            state:=2;
            inc(count);
          end;
        end;
      end;
      1:
      begin
        if val>h then
        begin
          state:=2;
          inc(count);
        end;
      end;
      2:
      begin
        if (val<l) then
        begin
          state:=0;
        end;
      end;
    end;
    t:=t+dt;
    res.SetY(i, count);
  end;

  wp.Link('/Signals/results', s.sname+'_'+'cnt', res as IDispatch);
  //if m_FltTrend then
  //begin
  //  wp.Link('/Signals/results', trendM.sname+'_'+'MO', trendM as IDispatch);
  //  wp.Link('/Signals/results', trendA.sname+'_'+'A', trendA as IDispatch);
  //end;

  winpos.Refresh;
  GetPropStr(wstr);
  winpos.AddTextInLog(c_OperName, wstr, true);
  winpos.DoEvents;


  pdst1 := res as IDispatch;
  pdst2 := nil;
end;

