function TCyclogramRepFrm.evaltriglist(hi, lo:double; first, b_hi, b_lo:boolean; s:cwpsignal):cTrigSetList;
var
  i:integer;
  v:double;
  trigval: sTrig;
  trig, lo_trig, startSensor:boolean;
begin
  result:=cTrigSetList.create;
  for i := 0 to s.Signal.size - 1 do
  begin
    v := s.Signal.GetY(i);
    // инициируем какие триги искать
    if i = 0 then
    begin
      if v > hi then
      begin
        trig := false;
        lo_trig := True;
        if first then
        begin
          trigval.trigValue := True;
          trigval.Time := s.Signal.GetX(i);
          result.add(trigval);
        end;
      end
      else
      begin
        if v < lo then
        begin
          trig := True;
          lo_trig := false;
        end
        else
        begin
          trig := True;
          lo_trig := True;
        end;
      end;
    end;
    // поиск фронтов
    if trig then
    begin
      if v > hi then
      begin
        trigval.Time := s.Signal.GetX(i);
        trigval.trigValue := True;
        if FrontCB.Checked then
          result.add(trigval);
        trig := false;
        lo_trig := True;
      end;
    end;
    startSensor:=(StartChanCB.text=s.name);
    // поиск спадов
    if lo_trig then
    begin
      if v < lo then
      begin
        // не нужно искать для сигнала обнуления времени
        if not startSensor  then
        begin
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := false;
          if FallCB.Checked then
            result.add(trigval);
        end;
        lo_trig := false;
        trig := True;
      end;
    end;
  end;
end;

function TCyclogramRepFrm.EvalDataTable(p: cpair): cSDataList;
var
  i: integer;
  v: double;
  // инитное значение
  Writefirst, find_low, find_hi, lo_trig, trig, startSensor: boolean;
  s: cwpsignal;
  TrigLevel, lo_TrigLevel: double;

  trigval: sTrig;
begin
  result := cSDataList.create;
  result.s := p;
  Writefirst := NullCB.Checked;
  // искать спады
  find_low := FallCB.Checked;
  // искать фронты
  find_hi := FrontCB.Checked;
  s := p.first;
  if s.Name = StartChanCB.Text then
    startSensor := True
  else
    startSensor := false;
  TrigLevel := p.Lvl1;
  lo_TrigLevel := p.lo_Lvl1;
  for i := 0 to s.Signal.size - 1 do
  begin
    v := s.Signal.GetY(i);
    // инициируем какие триги искать
    if i = 0 then
    begin
      if v > TrigLevel then
      begin
        trig := false;
        lo_trig := True;
        // первое значение пишем только для уровня "1"
        if Writefirst then
        begin
          trigval.firstval:=true;
          trigval.trigValue := True;
          trigval.Time := s.Signal.GetX(i);
          result.data.add(trigval);
        end;
      end
      else
      begin
        if v < lo_TrigLevel then
        begin
          trig := True;
          lo_trig := false;
        end
        else
        begin
          trig := True;
          lo_trig := True;
        end;
      end;
    end;
    if find_hi then
    begin
      // поиск фронтов
      if trig then
      begin
        if v > TrigLevel then
        begin
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := True;
          trigval.firstval:=false;
          if FrontCB.Checked then
            result.data.add(trigval);
          trig := false;
          lo_trig := True;
        end;
      end;
    end;
    // поиск спадов
    if find_low then
    begin
      if lo_trig then
      begin
        if v < lo_TrigLevel then
        begin
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := false;
          trigval.firstval:=false;
          if FallCB.Checked then
            result.data.add(trigval);
          lo_trig := false;
          trig := True;
        end;
      end;
    end;
  end;
  if startSensor then
    exit;
  s := p.second;
  TrigLevel := p.Lvl2;
  lo_TrigLevel := p.lo_Lvl2;
  if s <> nil then
  begin
    for i := 0 to s.Signal.size - 1 do
    begin
      v := s.Signal.GetY(i);
      // инициируем какие триги искать
      if i = 0 then
      begin
        if v > TrigLevel then
        begin
          trig := false;
          lo_trig := True;
          trigval.connectedTo:=-1;
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := True;
          trigval.firstval:=true;
          result.refData.add(trigval);
        end
        else
        begin
          if v < lo_TrigLevel then
          begin
            trig := True;
            lo_trig := false;
          end
          else
          begin
            trig := True;
            lo_trig := True;
          end;
        end;
      end;
      // поиск фронтов
      if trig then
      begin
        if v > TrigLevel then
        begin
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := True;
          trigval.firstval:=false;
          if FrontCB.Checked then
            result.refData.add(trigval);
          trig := false;
          lo_trig := True;
        end;
      end;
      // поиск спадов
      if lo_trig then
      begin
        if v < lo_TrigLevel then
        begin
          trigval.Time := s.Signal.GetX(i);
          trigval.trigValue := false;
          trigval.firstval:=false;
          if FallCB.Checked then
            result.refData.add(trigval);
          lo_trig := false;
          trig := True;
        end;
      end;
    end;
  end;
end;

