        .second.Signal.MinY) / 2 + cpair(li.data).second.Signal.MinY;
    ChansLV.SetSubItemByColumnName('Обратная связь',
      cpair(li.data).second.name, li);
    ChansLV.SetSubItemByColumnName('Триггер2', floattostr(cpair(li.data).Lvl2),
      li);
  end;
