function TFFTFltFrm.EditOper: string;
var
  res: integer;
  i: integer;
  p2:point2d;

  start, stop: integer;
  param: olevariant;
  wstr: widestring;
  s: iwpsignal;
  iD: idispatch;
  savestr,str:string;
  rec:LBRecord;
  li:tlistitem;
begin
  // переносим свойства в форму
  p2:=GetActiveCursorX;
  showSignals;
  load;
  res := showmodal;
  if res = mrok then
  begin
    save;
    m_oper.m_Band.Clear;
    for I := 0 to ScalesLV.Items.Count - 1 do
    begin
      li:=ScalesLV.Items[i];
      ScalesLV.GetSubItemByColumnName('F', li, str);
