procedure setSelItem(lv:tbtnlistview; str:string);
var
  I: Integer;
  li:tlistitem;
  sname:string;
begin
  for I := 0 to lv.items.Count - 1 do
  begin
    li:=lv.Items[i];
    lv.GetSubItemByColumnName('Сигналы', li, sname);
    if sname=str then
    begin
      li.Checked:=true;
      exit;
    end;
  end;
end;

procedure TFFTFltFrm.save;
var
  ifile:tinifile;
  j,I: Integer;
  li, next:tlistitem;
  str:string;
begin
  ifile:=TIniFile.Create(startdir+'Opers\fftflt.ini');
  ifile.WriteString('Main', 'LoadPath', LoadCfgCB.Text);
  ifile.WriteString('Main', 'SavePath', SaveCfgCB.Text);
  ifile.WriteInteger('Main', 'FFTPoint', pCountIE.IntNum);
  ifile.WriteInteger('Main', 'Offset', OffsetSE.Value);
  i:=0;
  for j := 0 to SignalsLV.items.Count - 1 do
  begin
    li:=SignalsLV.items[j];
    if li.Checked then
    begin
      str:=lbrecord(li.Data).s.SName;
      ifile.WriteString('Main', 'S_'+inttostr(i), str);
      inc(i);
    end;
  end;
  ifile.WriteInteger('Main', 'SCount', i);
  ifile.Destroy;
end;



procedure TFFTFltFrm.load;
var
  ifile:tinifile;
  I, selcount: Integer;
  s, sname:string;
begin
  ifile:=TIniFile.Create(startdir+'Opers\fftflt.ini');
  LoadCfgCB.Text:=ifile.ReadString('Main', 'LoadPath', '');
  if fileexists(LoadCfgCB.Text) then
    LoadBtnClick(nil);
  SaveCfgCB.Text:=ifile.ReadString('Main', 'SavePath', '');
  pCountIE.IntNum:=ifile.readInteger('Main', 'FFTPoint', 8192);
  OffsetSE.Value:=ifile.readInteger('Main', 'Offset', 8192);
  selcount:=ifile.readInteger('Main', 'SCount', 0);
  for I := 0 to selcount - 1 do
  begin
    s:='S_'+inttostr(i);
    sname:=ifile.ReadString('Main', s, '');
    setSelItem(SignalsLV, sname);
  end;
  ifile.Destroy;
  updatefs;
end;


procedure TFFTFltFrm.LoadBtnClick(Sender: TObject);
var
   I: Integer;
   str:string;
   f:TextFile;
   slist:tstringlist;
   li:TListItem;
begin
   if FileExists(LoadCfgCB.text) then
   begin
     slist:=TStringList.Create;
     slist.Delimiter:=';';
     System.Assign(f,LoadCfgCB.text);
     Reset(f);
     ScalesLV.Clear;

     while not Eof(f) do
     begin
       ReadLn(f,str);
       slist.DelimitedText:=str;
       li:=ScalesLV.Items.Add;
       ScalesLV.SetSubItemByColumnName('Инд.', inttostr(li.Index+1), li);
       ScalesLV.SetSubItemByColumnName('F', slist.Strings[0], li);
       ScalesLV.SetSubItemByColumnName('Scale', slist.Strings[1], li);
     end;

     LVChange(ScalesLV);
     slist.Destroy;
     CloseFile(f);
   end;
end;


procedure TFFTFltFrm.SaveBtnClick(Sender: TObject);
var
  I: Integer;
  li: TListItem;
  str, savestr:string;
  f:TextFile;
begin
  if SaveCfgCB.text='' then
    exit;
  str:=extractfiledir(SaveCfgCB.text);
  if not DirectoryExists(str) then
  begin
    ForceDirectories(str);
  end;
  System.Assign(f, SaveCfgCB.text);
  // открываем для записи
  Rewrite(f);
  for I := 0 to ScalesLV.items.Count - 1 do
  begin
    li:=ScalesLV.Items[i];
    ScalesLV.GetSubItemByColumnName('F', li, str);
    savestr:=str+';';
    ScalesLV.GetSubItemByColumnName('Scale', li, str);
    savestr:=savestr+str;
    // запись строки во второй файл
    writeln(f, savestr);
  end;
  CloseFile(f);
end;

procedure TFFTFltFrm.ScalesLVClick(Sender: TObject);
var
  // ссылка на данные компанента
  li,  next :TListItem;
  str:string;
  I, ind: Integer;
begin
  li:=ScalesLV.Selected;
  if li<>nil then
  begin
    ScalesLV.GetSubItemByColumnName('F', li, str);
    ind:=pos('..',str);
    f1se.Value:=StrtoFloatExt(copy(str,1,ind-1));
    f2se.Value:=StrtoFloatExt(copy(str,ind+2,length(str)-ind-1));
    ScalesLV.GetSubItemByColumnName('Scale', li, str);
    ScaleSE.Value:=StrtoFloatExt(str);
  end;
end;

procedure TFFTFltFrm.ScalesLVKeyDown(Sender: TObject; var Key: Word;
  Shift: TShiftState);
