  s: iwpsignal;
  str: string;
begin
  if FltEdit.text = '' then
  begin
    result := true;
    exit;
  end;
  result := false;
  s := nd.signal;
  if s <> nil then
  begin
    str := s.sname;
    result := pos(FltEdit.text, str) > 0;
  end
  else
  begin
    result := true;
  end;
end;

