function GetTBandFromStr(str: string): tband;
var
  j, col: integer;
  s: string;
  b: tband;
begin
  col := 0;
  b := tband.create;
  for j := 1 to length(str) do
  begin
    if str[j] <> ';' then
    begin
      s := s + str[j];
    end
    else
    begin
      case col of
        0:
          b.f1 := strtofloat(s);
        1:
          b.f2 := strtofloat(s);
        2:
          b.LevelPos := strtofloat(s);
        3:
          b.LevelNeg := strtofloat(s);
        4:
          b.NoisePos := strtofloat(s);
        5:
          b.NoiseNeg := strtofloat(s);
        6:
          begin
            if s = '+' then
              b.PosRes := true
            else
              b.PosRes := false;
          end;
        7:
          begin
            if s = '+' then
              b.NegRes := true
            else
              b.NegRes := false;
          end;
        8:
          begin
            // единицы
            if s = 'Абс.' then
            begin
              b.units := u_Abs;
            end;
            if s = '%' then
            begin
              b.units := u_percent;
            end;
            if s = '10Lg' then
            begin
              b.units := u_10Lg;
            end;
            if s = '20Lg' then
            begin
              b.units := u_20Lg;
            end;
          end;
        9:
          begin
            // единицы
            if s = '+' then
              b.MO_Offset := true
            else
              b.MO_Offset := false;
          end;
      end;
      inc(col);
      s := '';
    end;
  end;
  result := b;
end;

