  begin
    ifile := tinifile.create(path);
    NameEdit.Text := ifile.ReadString('Main', 'bandsPath', '');
    SavePathEdit.Text := ifile.ReadString('Main', 'SavePath', '');
    ifile.destroy;
  end;
  ImportBtnClick(nil);
