  UpdateInfo;
end;

Function TGenFrm.ShowModal:integer;
begin
  AmpRGClick(nil);
  FreqRGClick(nil);
  if inherited showmodal=mrok then
  begin
    case TabControl.ActivePageIndex of
      0:GenMeandr;
