procedure TRptFrm.EvalBandsByChannel;
var
  s:cwpsignal;
begin
  BandCountIE.IntNum:=0;
  s:=cwpsignal(GetComboBoxItem(autobandchannelcb));
  if s=nil then
    exit;
  TExtOperRpt(eo).m_autoBThreshold:=Threshold.FloatNum;
  TExtOperRpt(eo).EvalBandsByChannel(s);
