procedure testmnk;
var
  x, y, p: array of double;
  poly: integer;

  m1, m2, m3: d2array;
  i, j, c: integer;
begin
  setlength(m1, 3, 3);
  setlength(m2, 4, 3);
  c := 1;
  for i := 0 to 3 - 1 do
  begin
    for j := 0 to 3 - 1 do
    begin
      m1[i, j] := c;
      inc(c);
    end;
  end;
  c := 1;
  for i := 0 to 4 - 1 do
  begin
    for j := 0 to 3 - 1 do
    begin
      m2[i, j] := c;
      inc(c);
    end;
  end;
  MultMatrix(m1, m2, m3);

  poly := 2;
  setlength(x, 8);
  setlength(y, 8);
  setlength(p, poly + 1);

  x[0] := 0.72;
  y[0] := 0.53;
  x[1] := 0.99;
  y[1] := 1.10;
  x[2] := 1.11;
  y[2] := 1.22;
  x[3] := 1.76;
  y[3] := 3.22;
  x[4] := 1.86;
  y[4] := 3.91;
  x[5] := 2.55;
  y[5] := 6.23;
  x[6] := 3.24;
  y[6] := 9.06;
  x[7] := 4.53;
  y[7] := 2.32;

  buildMNK(poly, x, y, p);

end;

