  // graph := createline(gt, graph.hgraph, graph.haxis);
  graph := createlineNewAx(vt, graph.hgraph);
  graph := createline(gt, graph.hgraph, graph.haxis);
  normaliseGraph(graph.hgraph);
  result := graph;
end;

