function TRZDMatrix.Infostr: string;
begin
  result := formatstrNoE(m[0, 0], c_digits) + ';' + formatstrNoE(m[1, 0],
    c_digits) + ';' + formatstrNoE(m[2, 0], c_digits) + ';' + formatstrNoE
    (m[3, 0], c_digits);
end;

function TRZDMatrix.GetIniName: string;
begin
