function StringToDigCodeStr(str: string): string;
var
  ch: char;
  i, index: integer;
begin
  result := '';
  for i := 1 to length(str) do
  begin
    ch := str[i];
    index := pos(ch, u_chars);
    if index > 0 then
    begin
      if result = '' then
      begin
        // имя переменной не может начинаться с '_' поэтому в качестве первой скобки добавляем A_A
        result := 'A_A_' + inttostr(index) + '_';
      end
      else
      begin
        result := result + '_' + inttostr(index) + '_';
      end;
    end
    else
    begin
      result := result + ch;
    end;
  end;
end;

function DigCodeStrToString(str: string): string;
var
  ch: char;
  i, startbracketIndex: integer;
  // внутри скобок
  bracket, inbracket, newSubNum: boolean;
  substr: string;
begin
  result := '';
  bracket := false;
  newSubNum := false;
  startbracketIndex := 0;
  for i := 1 to length(str) do
  begin
    ch := str[i];
    if bracket = false then
    begin
      // входим в скобки
      if ch = '_' then
      begin
        bracket := true;
        substr := '';
        startbracketIndex := i;
      end;
    end;
    if bracket and (i <> startbracketIndex) then
    begin
      // выходим из скобок
      if ch = '_' then
      begin
        bracket := false;
        newSubNum := true;
      end;
    end;
    // если не в скобках
    if not bracket then
    begin
      // если скобки только что завершились
      if newSubNum then
      begin
        result := result + u_chars[strtoint(substr)];
        newSubNum := false;
      end
      else
      begin
        result := result + ch;
      end;
    end
    else
    begin
      if startbracketIndex = i then
      begin

      end
      else
        substr := substr + ch;
    end;
  end;
  if pos('A_A', result) = 1 then
  begin
    result := Copy(result, 4, length(result));
  end;
end;

