procedure TSelectIntervalFrm.evalAllTest;
var
  minmax:point2d;
  i:integer;
  s:cWPSignal;
  min, max:double;
begin
  for i := 0 to src.ChildCount - 1 do
  begin
    s := src.getSignalObj(i);
    if i = 0 then
    begin
      min := s.Signal.MinX;
      max := s.Signal.MaxX;
    end
    else
    begin
      if s.Signal.MinX > min then
        min := s.Signal.MinX;
      if s.Signal.MaxX < max then
        max := s.Signal.MaxX;
    end;
  end;
  minmax:=p2d(min,max);
  startT:=minmax.x;
  stopT:=minmax.y;
  starte.FloatNum:=minmax.x;
  StopE.FloatNum:=minmax.y;
  lengthe.FloatNum:=minmax.y-minmax.x;
end;

procedure TSelectIntervalFrm.EvalBtnClick(Sender: TObject);
var
  o1, o2:tobject;
  t1,t2:double;
begin
  ProgressBar1.Position:=0;
  if StartCB.ItemIndex>-1 then
  begin
    o1:=start;
    if tobject(o1) is ctrig then
    begin
      src.trigstart:=start;
      t1:=start.GetTime;
      if t1<startT then
        t1:=startT;
      StartE.FloatNum:=t1;
    end
    else
    begin
      t1:=startT;
    end;
  end;
  if StopCB.ItemIndex>-1 then
  begin
    o2:=stop;
    if tobject(o2) is ctrig then
    begin
      src.trigstop:=stop;
      t2:=stop.GetTime;
      if t2>stopT then
        t2:=stopT;
      StopE.FloatNum:=t2;
    end
    else
    begin
      t2:=stopT;
    end;
  end;
  ProgressBar1.Position:=0;
end;

