  chancb.clear;
  Startcb.clear;
  Stopcb.clear;
  for I := 0 to mng.TrigList.Count - 1 do
  begin
    t:=mng.getTrig(i);
    Startcb.Items.AddObject(t.id,t);
    Stopcb.Items.AddObject(t.id,t);
