// отсчитываем фазу только в положительном направлении (против часовой стрелки)
function GetPhase(r,i:single):single;
var
  // четверть
  c: integer;
begin
  if r>=0 then
  begin
    if r=0 then
    begin
      if i>0 then
        result:=90
      else
        result:=-90;
    end
    else
    begin
      result:=arctan(i/r)*180/pi;
      // 1-я четверть
