procedure TFxForm.ShowOpersSrc;
var
  I, ind: Integer;
  o:coperobj;
  srcID:selObj;
  str:string;
  src:csrc;
  list:tstringList;
begin
  OpersSrc.Clear;
  list:=TStringList.Create;
  list.Sorted:=true;
  for I := 0 to wp.opers.Count - 1 do
  begin
    o:=wp.GetOper(i);
    if not list.Find(o.SrcDir, ind) then
    begin
      srcID:=selObj.Create;
      srcID.s:=o.SrcDir;
      srcID.i:=o.srcId;
      list.AddObject(srcid.s,srcid);
    end;
    if not list.Find(o.DstDir, ind) then
    begin
      srcID:=selObj.Create;
      srcID.s:=o.DstDir;
      srcID.i:=o.DstId;
      list.AddObject(srcid.s,srcid);
    end;
  end;
  for I := 0 to List.Count - 1 do
  begin
    AddSrcToOpersLV(list.Objects[i]);
    selobj(list.Objects[i]).Destroy;
  end;
  LVChange(OpersSrc);
  list.Destroy;
end;

