uWPNameFilterFrame.pas:
// принимает на вход Tstringlist содержащий ссылки на список iwpsignals
    procedure setNames(l:TSignalArray);
    function getNames:TSignalArray;
    constructor create(AOwner: TComponent);override;
    destructor destroy;override;
  end;

  const
    c_NameFltOn ='UseNameFlt';
    c_NameFlt ='UseNameFlt';
    c_DscFltOn ='UseDscFlt';
    c_DscFlt ='UseDscFlt';
    c_PropFltOn ='UsePropFlt';
    c_PropFlt ='UsePropFlt';
    c_Props ='Свойство';
    c_Values ='Значения';

implementation

{$R *.dfm}
constructor TWPNameFltFrame.create(AOwner: TComponent);
begin
  inherited;
end;

destructor TWPNameFltFrame.destroy;
begin
  inherited;
end;

procedure TWPNameFltFrame.DscFltCBClick(Sender: TObject);
begin
  Updateselected;
end;

procedure TWPNameFltFrame.DscFltChange(Sender: TObject);
begin
  Updateselected;
end;

procedure TWPNameFltFrame.SaveCfg(section,cfgpath:string);
var
  ifile:tinifile;
  I: Integer;
  s, v:string;
  li:tlistitem;
begin
  ifile:=tinifile.create(cfgpath);
  ifile.WriteBool(section, c_NameFltOn, NameFltCB.checked);
  ifile.WriteString(section, c_NameFlt, NameFlt.text);
  ifile.WriteBool(section, c_dscFltOn, DscFltCB.checked);
  ifile.WriteString(section, c_DscFlt, DscFlt.text);
  ifile.WriteBool(section, c_PropFltOn, PropFltCB.checked);
  for I := 0 to PropList.items.Count - 1 do
  begin
    PropList.GetSubItemByColumnName(c_Props,li,s);
    PropList.GetSubItemByColumnName(c_Props,li,v);
    ifile.WriteString(section, '.'+s, v);
  end;
end;

procedure TWPNameFltFrame.ReadCfg(section,cfgpath:string);
var
  ifile:tinifile;
  I: Integer;
  s, v:string;
  li:tlistitem;
  slist:tstringlist;
begin
  ifile:=tinifile.create(cfgpath);
  NameFltCB.checked:=ifile.ReadBool(section, c_NameFltOn, false);
  NameFlt.text:=ifile.ReadString(section, c_NameFlt, '');
  DscFltCB.checked:=ifile.ReadBool(section, c_dscFltOn, false);
  DscFlt.text:=ifile.ReadString(section, c_DscFlt,'');
  PropFltCB.checked:=ifile.ReadBool(section, c_PropFltOn, false);
  slist:=TStringList.Create;
  ifile.ReadSections(slist);
  for I := 0 to sList.Count - 1 do
  begin
    s:=slist.Strings[i];
    if s[1]='.' then
    begin
      s:=Copy(s,2,length(s));
      li:=PropList.items.add;
      v:=ifile.ReadString(section, s, '');
      PropList.SetSubItemByColumnName(c_Props, s, li);
      PropList.SetSubItemByColumnName(c_Values, v, li);
    end;
  end;
end;

procedure TWPNameFltFrame.ShowSlist(l:TSignalArray);
var
  i: Integer;
  sig:iwpsignal;
begin
  clearSList;
  for i := 0 to length(l) - 1 do
  begin
    sig:=l[i];
    namesLB.AddItem(sig.sname,nil);
  end;
end;

procedure TWPNameFltFrame.setNames(l:TSignalArray);
begin
  siglist:=l;
  ShowSlist(l);
end;

function TWPNameFltFrame.getNames:TSignalArray;
var
  I: Integer;
begin
  setlength(siglist, length(selected));
  for I := 0 to length(selected) - 1 do
  begin
    siglist[i]:=selected[i];
  end;
  result:=siglist;
end;

procedure TWPNameFltFrame.NameFltCBClick(Sender: TObject);
begin
  Updateselected;
end;

procedure TWPNameFltFrame.NameFltChange(Sender: TObject);
begin
  Updateselected;
end;

procedure TWPNameFltFrame.clearSList;
begin
  NamesLB.Clear;
end;

procedure TWPNameFltFrame.Updateselected;
var
  I, j: Integer;
  li:tlistitem;
  s, prop, propval, propval1:string;
  sig:iwpsignal;
  b, propCheck:boolean;
  count:integer;
begin
  count:=length(siglist);
  setlength(selected, count);
  // кол-во прошедших фильтр сигналов
  count:=0;
  for I := 0 to length(siglist) - 1 do
  begin
    propcheck:=true;
    sig:=iwpsignal(siglist[i]);
    s:=sig.sname;
    b:=true;
    // если не нашли подстроку
    if NameFltCB.Checked then
    begin
      if NameFlt.text<>'' then
      begin
        if pos(NameFlt.text,s)<1 then
          continue;
      end;
    end;
    if DscFltCB.Checked then
    begin
      if DscFlt.text<>'' then
      begin
        if pos(DscFlt.text,sig.comment)<1 then
          continue;
      end;
    end;
    if PropFltCB.Checked then
    begin
      propCheck:=true;
      for j:= 0 to PropList.Items.Count - 1 do
      begin
        li:=PropList.Items[i];
        PropList.GetSubItemByColumnName(c_Props, li, prop);
        PropList.GetSubItemByColumnName(c_Values, li,propval);
        propval1:=sig.GetProperty(prop);
        if pos(propval, propval1)<1 then
        begin
          propcheck:=false;
          break;
        end;
      end;
    end;
    if not propcheck then
      Continue;
    selected[count]:=sig;
    inc(count);
  end;
  setlength(selected, count);
  ShowSlist(selected);
end;

end.

uWPSpmFrame.pas:
// тип окна
  SINGLEWIN       = 1;
  TRIANGLEWIN     = 2;
  HANNINGWIN      = 3;
  HANNINGWIN_RMS  = 4;
  BLACKMANWIN     = 5;
  BLACKMANWIN_RMS = 6;
  FLATTOP         = 7;
  FLATTOP_RMS     = 8;

  AMPLITUDE_SPM = 4; // амплитудный спектр
  SPM_SPM = 5; // спектр плотности мощности
  ImRe_SPM = 6;
  ModPhase_SPM = 7;

  MAG_RMS = 1; // СКЗ
  MAG_A = 2; // Амплитуда
  MAG_R = 3; // Размах

  c_numPoints = 'numPoints';
  C_SPMOPTS= 'kindFunc=4,numPoints=16384,nLines=0,typeWindow=1,typeMagnitude=1,type=0,method=0,isMO=1,isCorrectFunc=0,isMonFase=0,isFill0=1,fMaxVal=0,fLog=0,fPrSpec=0,f3D=0,iStandart=1,fFlt=0';


implementation

{$R *.dfm}

function strtobool(str:string):boolean;
begin
  result:=false;
  if str='1' then
    RESULT:=TRUE;
end;

procedure TWPSpmFrame.SetOpts(str:string);
var
  pars:tstringlist;
  i:integer;
begin
  if str<>'' then
    m_opts:=str
  else
    m_opts:=C_SPMOPTS;

  pars:=ParsStrParamNoSort(m_opts, ',');
  numpointscb.text:=GetParsValue(pars, c_numPoints);
  NulCB.checked:=strtobool(GetParsValue(pars,'isFill0'));
  i:=strtoint(GetParsValue(pars,'typeWindow'));
  case i of
    SINGLEWIN: wndCB.ItemIndex:=0;
    TRIANGLEWIN: wndCB.ItemIndex:=1;
    HANNINGWIN: wndCB.ItemIndex:=2;
    HANNINGWIN_RMS: wndCB.ItemIndex:=3;
    BLACKMANWIN: wndCB.ItemIndex:=4;
    BLACKMANWIN_RMS: wndCB.ItemIndex:=5;
    FLATTOP: wndCB.ItemIndex:=6;
    FLATTOP_RMS: wndCB.ItemIndex:=7;
  end;
  i:=strtoint(GetParsValue(pars,'kindFunc'));
  case i of
    AMPLITUDE_SPM:       SpmTypeCB.ItemIndex:=0;
    SPM_SPM:     SpmTypeCB.ItemIndex:=1;
    ImRe_SPM:      SpmTypeCB.ItemIndex:=2;
    ModPhase_SPM:  SpmTypeCB.ItemIndex:=3;
  end;
  i:=strtoint(GetParsValue(pars,'typeMagnitude'));
  case i of
    MAG_RMS:  SpmResCB.ItemIndex:=0;
    MAG_A:  SpmResCB.ItemIndex:=1;
    MAG_R:  SpmResCB.ItemIndex:=2;
  end;
  pars.destroy;
end;

function TWPSpmFrame.GetOpts:string;
var
  pars:tstringlist;
  ind:integer;
  v:cString;
  str:string;
begin
  pars:=ParsStrParamNoSort(m_opts, ',');
  if FindInPars(pars, c_numPoints, ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    v.str:=numpointscb.text;
  end;
  if FindInPars(pars,'isFill0',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    if NulCB.checked then
      v.str:='1'
    else
      v.str:='0';
  end;
  if FindInPars(pars,'typeWindow',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    case wndCB.itemindex of
      0: v.str:=inttostr(SINGLEWIN);
      1: v.str:=inttostr(TRIANGLEWIN);
      2: v.str:=inttostr(HANNINGWIN);
      3: v.str:=inttostr(HANNINGWIN_RMS);
      4: v.str:=inttostr(BLACKMANWIN);
      5: v.str:=inttostr(BLACKMANWIN_RMS);
      6: v.str:=inttostr(FLATTOP);
      7: v.str:=inttostr(FLATTOP_RMS);
    end;
  end;
  if FindInPars(pars,'kindFunc',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    case SpmTypeCB.itemindex of
      0: v.str:=inttostr(AMPLITUDE_SPM);
      1: v.str:=inttostr(SPM_SPM);
      2: v.str:=inttostr(ImRe_SPM);
      3: v.str:=inttostr(ModPhase_SPM);
    end;
  end;
  if FindInPars(pars,'typeMagnitude',ind) then
  begin
    v:=cstring(pars.Objects[ind]);
    case SpmResCB.itemindex of
      0: v.str:=inttostr(MAG_A);
      1: v.str:=inttostr(MAG_R);
      2: v.str:=inttostr(MAG_RMS);
    end;
  end;
  str:=ParsToStr(pars);
  result:=str;
  pars.Destroy;
end;

end.
